content.text:
Colle ce script dans **PowerShell local** (pas dans le chat), il va scanner, détecter les projets fiables, ouvrir chaque projet dans une fenêtre Cursor séparée, puis afficher le résumé :

```powershell
$ErrorActionPreference = "SilentlyContinue"

# 1) Localiser Cursor.exe
$cursorCandidates = @(
  "$env:LOCALAPPDATA\Programs\Cursor\Cursor.exe",
  "C:\Program Files\Cursor\Cursor.exe",
  "$env:USERPROFILE\scoop\apps\cursor\current\Cursor.exe"
)
$CursorExe = $cursorCandidates | Where-Object { Test-Path $_ } | Select-Object -First 1
if (-not $CursorExe) {
  Write-Host "Cursor.exe introuvable. Installe Cursor ou adapte le chemin dans le script." -ForegroundColor Red
  exit 1
}

# 2) Racines à scanner
$desktop   = [Environment]::GetFolderPath("Desktop")
$documents = [Environment]::GetFolderPath("MyDocuments")
$downloads = Join-Path $env:USERPROFILE "Downloads"

$roots = @($desktop, $documents, $downloads, "C:\")

# Dossiers potentiellement transferes depuis ancien PC
$legacyPattern = '(?i)(old|ancien|backup|transf|migrat|copie|clone|ancien\s*pc|old\s*pc)'
foreach ($base in @($desktop, $documents, $downloads, "C:\Users", "D:\", "E:\", "F:\", "G:\")) {
  if (Test-Path $base) {
    $roots += Get-ChildItem -Path $base -Directory -Force |
      Where-Object { $_.Name -match $legacyPattern } |
      Select-Object -ExpandProperty FullName
  }
}

# Disques externes connectes
$drives = Get-PSDrive -PSProvider FileSystem | Select-Object -ExpandProperty Root
$externalRoots = $drives | Where-Object { $_ -ne "C:\" }
$roots += $externalRoots

$roots = $roots | Where-Object { $_ -and (Test-Path $_) } | Sort-Object -Unique

# 3) Detection projets
$excludeDirs = @("node_modules","dist","build",".next",".git",".cache","coverage","out","target","bin","obj")

function Is-ExcludedPath([string]$path) {
  $p = $path.ToLowerInvariant()
  foreach ($d in $excludeDirs) {
    if ($p -match "(\\|/)$([regex]::Escape($d))(\\|/|$)") { return $true }
  }
  return $false
}

function Marker-Exists([string]$root, [string]$rel) {
  $p = Join-Path $root $rel
  Test-Path $p
}

$projectCandidates = @()

foreach ($r in $roots) {
  Write-Host "Scan: $r"
  # On cible package.json + tsconfig + app.json + vite/next + README pour remonter vers la racine projet
  $files = Get-ChildItem -Path $r -Recurse -File -Force |
    Where-Object {
      -not (Is-ExcludedPath $_.FullName) -and (
        $_.Name -in @("package.json","tsconfig.json","app.json","README.md","vite.config.js","vite.config.ts","next.config.js","next.config.mjs")
      )
    }

  foreach ($f in $files) {
    $dir = $f.Directory
    $candidate = $null
    while ($dir) {
      if (Is-ExcludedPath $dir.FullName) { break }
      if (Test-Path (Join-Path $dir.FullName ".git")) { $candidate = $dir.FullName; break }
      if (Test-Path (Join-Path $dir.FullName "package.json")) { $candidate = $dir.FullName; break }
      if (Test-Path (Join-Path $dir.FullName "tsconfig.json")) { $candidate = $dir.FullName; break }
      $dir = $dir.Parent
    }
    if (-not $candidate) { $candidate = $f.Directory.FullName }
    if (-not (Is-ExcludedPath $candidate)) {
      $projectCandidates += $candidate
    }
  }
}

$projectCandidates = $projectCandidates | Sort-Object -Unique

# 4) Qualification fiable / douteux
$reliable = @()
$ignored  = @()

foreach ($p in $projectCandidates) {
  if (-not (Test-Path $p)) { continue }

  $markers = @()
  if (Test-Path (Join-Path $p ".git")) { $markers += ".git" }
  if (Test-Path (Join-Path $p "package.json")) { $markers += "package.json" }
  if (Test-Path (Join-Path $p "tsconfig.json")) { $markers += "tsconfig.json" }
  if (Test-Path (Join-Path $p "README.md")) { $markers += "README.md" }
  if (Test-Path (Join-Path $p "vite.config.js")) { $markers += "vite.config.js" }
  if (Test-Path (Join-Path $p "vite.config.ts")) { $markers += "vite.config.ts" }
  if (Test-Path (Join-Path $p "next.config.js")) { $markers += "next.config.js" }
  if (Test-Path (Join-Path $p "next.config.mjs")) { $markers += "next.config.mjs" }
  if (Test-Path (Join-Path $p "app.json")) { $markers += "app.json" }
  foreach ($d in @("src","app","pages","components","expo")) {
    if (Test-Path (Join-Path $p $d)) { $markers += $d }
  }

  $hasGit = $markers -contains ".git"
  $hasPkg = $markers -contains "package.json"
  $hasTs  = $markers -contains "tsconfig.json"
  $hasAppStruct = ($markers | Where-Object { $_ -in @("src","app","pages","components","expo") }).Count -gt 0

  $isReliable = (($hasGit -and ($hasPkg -or $hasTs)) -or ($hasPkg -and $hasAppStruct))

  if ($isReliable) {
    $reliable += [PSCustomObject]@{ Path=$p; Markers=($markers | Sort-Object -Unique) }
  } else {
    $ignored += [PSCustomObject]@{ Path=$p; Markers=($markers | Sort-Object -Unique); Reason="incomplet_ou_douteux" }
  }
}

$reliable = $reliable | Sort-Object Path -Unique

# 5) Ouvrir chaque projet fiable dans une fenetre Cursor separée
$opened = @()
foreach ($proj in $reliable) {
  Start-Process -FilePath $CursorExe -ArgumentList @("--new-window", $proj.Path)
  $opened += $proj.Path
}

# 6) Resume final
Write-Host ""
Write-Host "===== RESUME =====" -ForegroundColor Cyan
Write-Host ("Nombre de projets ouverts: " + $opened.Count) -ForegroundColor Green
Write-Host ""
Write-Host "Projets ouverts :" -ForegroundColor Yellow
$opened | ForEach-Object { Write-Host " - $_" }

Write-Host ""
Write-Host "Projets ignores (incomplets/douteux) :" -ForegroundColor Yellow
if ($ignored.Count -eq 0) {
  Write-Host " - Aucun"
} else {
  $ignored | ForEach-Object {
    Write-Host (" - " + $_.Path + " [" + ($_.Markers -join ", ") + "]")
  }
}
```

Si tu veux, je peux aussi te donner une version qui **enregistre le résumé dans un fichier `.txt`** automatiquement.
